                val inputValue = if (value != null && value != "null") {
                    // Remove surrounding quotes and unescape
                    value.trim().removeSurrounding("\"").let { decodeUrl(it) }
                } else {
                    ""
                }
                typeAnswer!!.input = inputValue
                displayCardAnswer()
            }
        } else {
            displayCardAnswer()
        }
    }

