package com.ichi2.anki

import androidx.test.ext.junit.runners.AndroidJUnit4
import com.ichi2.anki.cardviewer.TypeAnswer
import com.ichi2.testutils.JvmTest
import org.hamcrest.MatcherAssert.assertThat
import org.hamcrest.Matchers.containsString
import org.junit.Test
import org.junit.runner.RunWith

/**
 * Test for the bug fix: Answer comparison not shown when type answer into the card is enabled
 * 
 * This test verifies that the TypeAnswer.filterAnswer method correctly generates
 * comparison HTML when both user input and correct answer are provided.
 */
@RunWith(AndroidJUnit4::class)
class TypeAnswerInputCaptureTest : JvmTest() {

    @Test
    fun `filterAnswer generates comparison when input is provided`() {
        val typeAnswer = TypeAnswer(
            useInputTag = true,
            doNotUseCodeFormatting = false,
            autoFocus = false
        )

        // Set the correct answer
        typeAnswer.apply {
            // Using reflection to set the correct answer since updateInfo requires a Collection
            val correctField = TypeAnswer::class.java.getDeclaredField("correct")
            correctField.isAccessible = true
            correctField.set(this, "hello")

            // Set the user input
            input = "hello"
        }

        val answerHtml = "[[type:Back]]"
        val result = typeAnswer.filterAnswer(answerHtml)

        // The result should contain the comparison HTML
        assertThat("Result should contain typeGood class for correct answer", 
            result, containsString("typeGood"))
        assertThat("Result should contain the answer text", 
            result, containsString("hello"))
    }

    @Test
    fun `filterAnswer generates comparison for incorrect answer`() {
        val typeAnswer = TypeAnswer(
            useInputTag = true,
            doNotUseCodeFormatting = false,
            autoFocus = false
        )

        // Set the correct answer
        typeAnswer.apply {
            val correctField = TypeAnswer::class.java.getDeclaredField("correct")
            correctField.isAccessible = true
            correctField.set(this, "hello")

            // Set incorrect user input
            input = "helo"
        }

        val answerHtml = "[[type:Back]]"
        val result = typeAnswer.filterAnswer(answerHtml)

        // The result should contain the comparison HTML with error indication
        assertThat("Result should contain typeBad class for incorrect answer", 
            result, containsString("typeBad"))
        assertThat("Result should contain the typed answer", 
            result, containsString("helo"))
    }

    @Test
    fun `filterAnswer with empty input shows only correct answer`() {
        val typeAnswer = TypeAnswer(
            useInputTag = true,
            doNotUseCodeFormatting = false,
            autoFocus = false
        )

        // Set the correct answer
        typeAnswer.apply {
            val correctField = TypeAnswer::class.java.getDeclaredField("correct")
            correctField.isAccessible = true
            correctField.set(this, "hello")

            // Set empty user input (simulating the bug scenario)
            input = ""
        }

        val answerHtml = "[[type:Back]]"
        val result = typeAnswer.filterAnswer(answerHtml)

        // When input is empty, it should still show the correct answer
        assertThat("Result should contain the correct answer", 
            result, containsString("hello"))
    }

    @Test
    fun `filterAnswer with special characters`() {
        val typeAnswer = TypeAnswer(
            useInputTag = true,
            doNotUseCodeFormatting = false,
            autoFocus = false
        )

        // Test with special characters that might need escaping
        typeAnswer.apply {
            val correctField = TypeAnswer::class.java.getDeclaredField("correct")
            correctField.isAccessible = true
            correctField.set(this, "hello \"world\"")

            // Set user input with quotes
            input = "hello \"world\""
        }

        val answerHtml = "[[type:Back]]"
        val result = typeAnswer.filterAnswer(answerHtml)

        // The result should contain the comparison with proper escaping
        assertThat("Result should contain typeGood class for correct answer", 
            result, containsString("typeGood"))
    }
}
"}

